#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (!s || !out)
        return 0;

    /* skip leading whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s == '\0')
        return 0;

    /* detect sign */
    int sign = 1;
    if (*s == '-') {
        sign = -1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (*s == '\0')
        return 0;

    /* parse digits */
    int32_t acc = 0;
    int32_t limit = (sign == 1) ? INT32_MAX : INT32_MIN;

    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';

        /* check overflow before multiplying and adding */
        if (sign == 1) {
            if (acc > (INT32_MAX - digit) / 10)
                return 0;
        } else {
            /* INT32_MIN is -2147483648, abs(INT32_MIN) = 2147483648 */
            /* We accumulate as negative to avoid abs(INT32_MIN) issue */
            if (acc < (INT32_MIN + digit) / 10)
                return 0;
        }

        acc = acc * 10 + digit * sign;

        /* early underflow/overflow check for negative path */
        if (sign == -1 && acc > 0)
            return 0;

        s++;
    }

    /* skip trailing whitespace */
    while (isspace((unsigned char)*s))
        s++;

    if (*s != '\0')
        return 0; /* extra non-whitespace characters */

    *out = acc;
    return 1;
}

